class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        long long res = target;
        int ops = 0;
        while (res != x) {
            if (res < x) {
                res *= x;
                ops++;
            } else {
                res /= x;
                ops++;
            }
        }
        return ops;
    }
};
